    // 1. Find all indices for 1s and 2s
    for (int i = 0; i < n; ++i) {
        if (nums[i] == 1) {
            ones_indices.push_back(i);
        } else if (nums[i] == 2) {
            twos_indices.push_back(i);
        }
    }

    // 2. Check if any valid pair exists
    if (ones_indices.empty() || twos_indices.empty()) {
        return -1;
    }

    // 3. Calculate the minimum absolute difference
    long long min_diff = numeric_limits<long long>::max();

    // Since we need the minimum difference between any i from ones_indices and any j from twos_indices,
    // a brute-force check over all pairs (O(N1 * N2)) is sufficient given N <= 100.
    for (int i_idx : ones_indices) {
        for (int j_idx : twos_indices) {
            long long diff = abs(i_idx - j_idx);
            if (diff < min_diff) {
                min_diff = diff;
            }
        }
    }

    return min_diff;
}

