/**
 * @brief Finds the minimum absolute difference between indices i and j such that nums[i] == 1 and nums[j] == 2.
 * 
 * @param nums The input array containing only 0, 1, and 2.
 * @return long long The minimum absolute difference, or -1 if no valid pair exists.
 */
long long solve(std::vector<long long> nums) {
    std::vector<int> ones_indices;
    std::vector<int> twos_indices;
    int n = nums.size();

    // Collect indices for 1s and 2s
    for (int i = 0; i < n; ++i) {
        if (nums[i] == 1) {
            ones_indices.push_back(i);
        } else if (nums[i] == 2) {
            twos_indices.push_back(i);
        }
    }

    // Check if at least one '1' and one '2' exist
    if (ones_indices.empty() || twos_indices.empty()) {
        return -1;
    }

    // Initialize minimum difference to a very large value
    long long min_diff = std::numeric_limits<long long>::max();

    // Iterate through all pairs (i, j) where i is index of 1 and j is index of 2
    for (int i_idx : ones_indices) {
        for (int j_idx : twos_indices) {
            // Calculate absolute difference
            long long diff = std::abs(i_idx - j_idx);

            // Update minimum difference
            if (diff < min_diff) {
                min_diff = diff;
            }
        }
    }

    // Return the minimum difference found
    return min_diff;
}
